```class Solution {
    public int maxSatisfied(int[] customers, int[] grumpy, int minutes) {
        int total = 0, maxExtra = 0;
        for (int i = 0; i < customers.length; i++) {
            if (grumpy[i] == 0) {
                total += customers[i];
            } else {
                maxExtra += customers[i];
            }
        }
        for (int i = 0; i < customers.length - minutes + 1; i++) {
            maxExtra = Math.max(maxExtra, customers[i + minutes - 1] + customers[i] + customers[i + 1] + ... + customers[i + minutes - 2]);
        }
        return total + Math.max(0, maxExtra - minutes * customers[0]);
    }
}
